    glossary: [{"term":"Raymarching","def":"stepping along a ray through a distance field until a surface is found"},{"term":"SDF","def":"signed distance function — math that describes shapes for raymarchers"},{"term":"Refraction","def":"bending of the view through transparent water"},{"term":"Shadertoy","def":"online playground for pixel/raymarch shaders (original by P_Malin)"},{"term":"Guided tour Step 3","def":"on /demos/panorama-360/ — cam · +particles/spout · hotspot+popup"}],
